// Multi-source job discovery (6 APIs)
const DEV = ['developer','engineer','programming','software','backend','back-end','fullstack','php','laravel','symfony'];
const EXCL = ['wordpress only','ios developer','android developer','mobile developer'];
const match = (t,d,e='') => { const x=`${t} ${d||''} ${e}`.toLowerCase(); return DEV.some(k=>x.includes(k)) && !EXCL.some(k=>x.includes(k)); };
const strip = s => (s||'').replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim();
const UA = { 'User-Agent': 'job-agent/1.0' };
const all = [];
const stats = {};

async function add(jobs, source) {
  let n = 0;
  for (const j of jobs) {
    if (!j.url || !j.title) continue;
    all.push({ json: j });
    n++;
  }
  stats[source] = n;
}

// 1. Remotive
try {
  const r = await this.helpers.httpRequest({ method:'GET', url:'https://remotive.com/api/remote-jobs?category=software-dev', json:true });
  const jobs = (r.jobs||[]).filter(j=>match(j.title,j.description,j.category)).slice(0,50).map(j=>({
    title:j.title, company:j.company_name, url:j.url, description:(j.description||'').slice(0,2000),
    source:'remotive', location:j.candidate_required_location||'Remote', salary:j.salary||null
  }));
  await add(jobs,'remotive');
} catch(e) { stats.remotive='err'; }

// 2. We Work Remotely RSS
try {
  const xml = await this.helpers.httpRequest({ method:'GET', url:'https://weworkremotely.com/categories/remote-programming-jobs.rss', json:false });
  const text = typeof xml === 'string' ? xml : '';
  const jobs = [];
  const re = /<item>([\s\S]*?)<\/item>/g; let m;
  while ((m=re.exec(text))!==null && jobs.length<30) {
    const item=m[1];
    const title=(item.match(/<title><!\[CDATA\[(.+?)\]\]><\/title>/)||item.match(/<title>(.+?)<\/title>/)||[])[1]||'';
    const link=(item.match(/<link>(.+?)<\/link>/)||[])[1]||'';
    const desc=strip((item.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/)||item.match(/<description>([\s\S]*?)<\/description>/)||[])[1]||'');
    if(!title||!link||!match(title,desc)) continue;
    const parts=title.split(':');
    jobs.push({ title:parts[0].trim(), company:parts[1]?.trim()||'Unknown', url:link, description:desc.slice(0,2000), source:'weworkremotely', location:'Remote', salary:null });
  }
  await add(jobs,'wwr');
} catch(e) { stats.wwr='err'; }

// 3. Arbeitnow
try {
  const r = await this.helpers.httpRequest({ method:'GET', url:'https://www.arbeitnow.com/api/job-board-api', json:true });
  const jobs = (r.data||[]).filter(j=>{ const t=`${j.title} ${j.description||''} ${(j.tags||[]).join(' ')}`; return match(j.title,j.description) && (j.remote||t.toLowerCase().includes('remote')); }).slice(0,30).map(j=>({
    title:j.title, company:j.company_name, url:j.url, description:(j.description||'').slice(0,2000),
    source:'arbeitnow', location:j.location||'Remote', salary:j.salary||null
  }));
  await add(jobs,'arbeitnow');
} catch(e) { stats.arbeitnow='err'; }

// 4. RemoteOK
try {
  const r = await this.helpers.httpRequest({ method:'GET', url:'https://remoteok.com/api', headers:UA, json:true });
  const arr = Array.isArray(r) ? r : [];
  const jobs = arr.filter(j=>j&&j.position&&match(j.position,j.description,(j.tags||[]).join(' '))).slice(0,30).map(j=>({
    title:j.position, company:j.company||'Unknown', url:j.url||j.apply_url, description:strip(j.description).slice(0,2000),
    source:'remoteok', location:j.location||'Remote', salary:j.salary_min?`${j.salary_min}-${j.salary_max}`:null
  }));
  await add(jobs,'remoteok');
} catch(e) { stats.remoteok='err'; }

// 5. Jobicy
try {
  const r = await this.helpers.httpRequest({ method:'GET', url:'https://jobicy.com/api/v2/remote-jobs?count=50&tag=dev', json:true });
  const jobs = (r.jobs||[]).filter(j=>match(j.jobTitle,j.jobExcerpt,(j.jobIndustry||[]).join(' '))).slice(0,30).map(j=>({
    title:j.jobTitle, company:j.companyName||'Unknown', url:j.url, description:strip(j.jobDescription||j.jobExcerpt).slice(0,2000),
    source:'jobicy', location:j.jobGeo||'Remote', salary:null
  }));
  await add(jobs,'jobicy');
} catch(e) { stats.jobicy='err'; }

// 6. Himalayas
try {
  const r = await this.helpers.httpRequest({ method:'GET', url:'https://himalayas.app/jobs/api?limit=50', json:true });
  const jobs = (r.jobs||[]).filter(j=>{
    if(!match(j.title,j.excerpt,(j.categories||[]).join(' '))) return false;
    const locs=j.locationRestrictions||[];
    if(locs.length===1 && locs[0].toLowerCase().includes('united states')) return false;
    return true;
  }).slice(0,30).map(j=>({
    title:j.title, company:j.companyName||'Unknown', url:j.applicationLink||j.guid, description:(j.excerpt||'').slice(0,2000),
    source:'himalayas', location:(j.locationRestrictions||[]).join(', ')||'Remote',
    salary:j.minSalary?`${j.minSalary}-${j.maxSalary||''} ${j.currency||''}`:null
  }));
  await add(jobs,'himalayas');
} catch(e) { stats.himalayas='err'; }

// Dedupe by URL
const seen = new Set();
const unique = all.filter(item => { if(seen.has(item.json.url)) return false; seen.add(item.json.url); return true; });

console.log('Discovery stats:', JSON.stringify(stats), 'total:', unique.length);
return unique;

const knownUrls = new Set($input.first()?.json?.urls || []);
const allJobs = $('Discover All Sources').all();
const newJobs = allJobs.filter(item => item.json.url && !knownUrls.has(item.json.url));
console.log(`Found ${allJobs.length} total, ${newJobs.length} new`);
return newJobs;

const secret = $env.N8N_WEBHOOK_SECRET;
if (!secret) throw new Error('Set N8N_WEBHOOK_SECRET in n8n environment variables');
const jobs = $input.first().json.jobs;
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://job-agent-eosin.vercel.app/api/jobs/ingest',
  headers: { Authorization: `Bearer ${secret}`, 'Content-Type': 'application/json' },
  body: jobs,
  json: true,
});
return [{ json: response }];
